import React, { useState, createContext, useContext } from 'react';
import { ToneMode } from '../components/utils/dmdb.props';

interface ThemeContent {
	themeSelected: ToneMode;
	themeBgClassName: string;
	themeTextClassName: string;
	lighterThemeBgClassName: string;
	movieProfileHoverTheme: string;
}

interface ThemeOptions {
	night: ThemeContent;
	light: ThemeContent
}

interface ThemeContextProps {
	theme: ThemeContent;
	setTheme: React.Dispatch<React.SetStateAction<ThemeContent>>;
}

export const themeOption: ThemeOptions = {
	night: {
		themeSelected: 'night',
		themeBgClassName: 'bg-slate-900',
		themeTextClassName: 'text-white',
		lighterThemeBgClassName: 'bg-slate-800',
		movieProfileHoverTheme: 'bg-slate-600'
	},
	light: {
		themeSelected: 'light',
		themeBgClassName: 'bg-slate-100',
		themeTextClassName: 'text-slate-800',
		lighterThemeBgClassName: 'bg-slate-200',
		movieProfileHoverTheme: 'bg-slate-400'
	}
};

export const ThemeContext = createContext<ThemeContextProps>({} as ThemeContextProps);

export default function ThemeContextProvider({ children }: any) { // não sei como tipar
	const [theme, setTheme] = useState<ThemeContent>(themeOption[getThemeFromLocalStorage()]);

	return <ThemeContext.Provider value={{ theme, setTheme }}>{children}</ThemeContext.Provider>;
}

export function useTheme() {
	const { theme, setTheme } = useContext(ThemeContext);
	return { theme, setTheme };
}

function getThemeFromLocalStorage() {
	const theme = localStorage.getItem('dmdb-theme');

	if (theme && (theme === 'light' || theme === 'night')) {
		return theme;
	}

	return 'night';
}
